import{_ as i,D as s,c as e,I as t,a2 as p,o as d}from"./chunks/framework.DwDoyBw8.js";const b=JSON.parse('{"title":"图片边框","description":"","frontmatter":{},"headers":[],"relativePath":"CSS/效果提升/图片边框.md","filePath":"learn/CSS/效果提升/图片边框.md","lastUpdated":1729069680000}'),n={name:"CSS/效果提升/图片边框.md"},l=p(`<h1 id="图片边框" tabindex="-1">图片边框 <a class="header-anchor" href="#图片边框" aria-label="Permalink to &quot;图片边框&quot;">​</a></h1><h2 id="效果图" tabindex="-1">效果图 <a class="header-anchor" href="#效果图" aria-label="Permalink to &quot;效果图&quot;">​</a></h2><p>效果如下图所示：</p><p><img src="https://pic.imgdb.cn/item/670f702ed29ded1a8c00dbf3.png" alt="效果图"></p><p>可以看到，边框是由图片实现的。</p><h2 id="实现" tabindex="-1">实现 <a class="header-anchor" href="#实现" aria-label="Permalink to &quot;实现&quot;">​</a></h2><p>想要实现这个功能，仅仅需要两行代码。</p><p>首先设置边框 <code>border</code> ，然后设置边框图片 <code>border-image</code> ，接收三个参数，图片的 SVG 路径，图片剪切距离，图片的裁剪效果。</p><p>代码如下所示：</p><div class="language-css vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">css</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">div</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  border</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">50</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">px</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> soild </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">#fff</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  border-image</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">url</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;./xxx.svg&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">50</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> round</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><h2 id="原理" tabindex="-1">原理 <a class="header-anchor" href="#原理" aria-label="Permalink to &quot;原理&quot;">​</a></h2><p>实际上 <code>border-image</code> 是一个复合属性，它拆分为以下三个属性：</p><ul><li><p><code>border-image-source</code> 图片源</p><p>如果单单设置这个属性，它只会在 <code>div</code> 的四个角添加图片效果，如下图所示：</p><p><img src="https://pic.imgdb.cn/item/670f7510d29ded1a8c04cf4d.png" alt="四个角"></p></li><li><p><code>border-image-slice</code> 图片切割</p><p>这个属性用于设置图片的切割，切割的原理如下图</p><p><img src="https://pic.imgdb.cn/item/670f75a8d29ded1a8c053d3a.png" alt="切割"></p><p>它如果设置一个值则表示全部这么切割，也可以像 <code>padding</code> 、<code>margin</code> 那样设置四个值。</p><p>以上方示例代码的方式，切割出来的效果是四个角加上四条边。</p></li><li><p><code>border-image-repeat</code> 边框过渡</p><p>该值用于控制中间的重复方式，默认为拉伸 <code>stretch</code> ，如果盒子过长则拉伸，如果过小则压缩。效果如下：</p><p><img src="https://pic.imgdb.cn/item/670f76a1d29ded1a8c05ff40.png" alt="拉伸"></p><p>一种是重复 <code>repeat</code> ，效果如下：</p><p><img src="https://pic.imgdb.cn/item/670f76f5d29ded1a8c0639c0.png" alt="重复"></p><p>重复 <code>repeat</code> 的效果和环绕 <code>round</code> 的效果咋一看很相似，但是 <code>repeat</code> 设置的边框他是以中心点为原点，如果有超出的部分，两侧与角的交界处会对不齐。因此上方的效果图可以看出四个角附近有一点不连贯的感觉。</p></li></ul><h2 id="总体效果" tabindex="-1">总体效果 <a class="header-anchor" href="#总体效果" aria-label="Permalink to &quot;总体效果&quot;">​</a></h2>`,14);function r(h,c,o,k,g,m){const a=s("Iframe");return d(),e("div",null,[l,t(a,{url:"https://duyidao.github.io/blogweb/#/detail/css/imageBorder"})])}const _=i(n,[["render",r]]);export{b as __pageData,_ as default};
